import time
import functools
from typing import Any, Callable, Tuple, TypeVar, cast

T = TypeVar('T')
F = TypeVar('F', bound=Callable[..., Any])

def retry(
    max_attempts: int = 3,
    backoff_factor: int = 2,
    exceptions: Tuple[Exception, ...] = (Exception,)
) -> Callable[[F], F]:
    """
    Decorator that retries a function call if it raises one of the specified exceptions.
    Uses exponential backoff between retries.

    Args:
        max_attempts: Maximum number of attempts to call the function (default is 3).
        backoff_factor: Factor by which the delay increases after each failed attempt (default is 2).
        exceptions: Tuple of exception classes that trigger a retry (default is (Exception,)).

    Returns:
        The decorated function that will be retried in case of the specified exceptions.
    """
    def decorator(func: F) -> F:
        @functools.wraps(func)
        def wrapper(*args: Any, **kwargs: Any) -> Any:
            delay = 1
            for attempt in range(1, max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as exc:
                    if attempt == max_attempts:
                        # Re-raise the exception if max attempts reached.
                        raise
                    time.sleep(delay)
                    delay *= backoff_factor
        return cast(F, wrapper)
    return decorator

# Example usage:
if __name__ == '__main__':
    import random

    @retry(max_attempts=5, backoff_factor=2, exceptions=(ValueError,))
    def unreliable_function() -> int:
        """A function that randomly fails to demonstrate the retry mechanism."""
        if random.random() < 0.7:
            print("Function failed, attempting retry...")
            raise ValueError("Random failure occurred")
        print("Function succeeded!")
        return 42

    try:
        result = unreliable_function()
        print("Result:", result)
    except ValueError as err:
        print("Function ultimately failed with error:", err)

